+func TestCalculateImbalanceScore(t *testing.T) {
+	tests := []struct {
+		name      string
+		workloads []RebalanceWorkload
+		want      float64
+		tolerance float64
+	}{
+		{
+			name:      "empty workloads",
+			workloads: []RebalanceWorkload{},
+			want:      0,
+			tolerance: 0.001,
+		},
+		{
+			name: "single workload",
+			workloads: []RebalanceWorkload{
+				{Pane: 1, TaskCount: 5},
+			},
+			want:      0, // stddev/mean = 0/5 = 0
+			tolerance: 0.001,
+		},
+		{
+			name: "perfectly balanced",
+			workloads: []RebalanceWorkload{
+				{Pane: 1, TaskCount: 3},
+				{Pane: 2, TaskCount: 3},
+				{Pane: 3, TaskCount: 3},
+			},
+			want:      0,
+			tolerance: 0.001,
+		},
+		{
+			name: "moderate imbalance",
+			workloads: []RebalanceWorkload{
+				{Pane: 1, TaskCount: 4},
+				{Pane: 2, TaskCount: 2},
+				{Pane: 3, TaskCount: 3},
+			},
+			// mean = 3, variance = ((4-3)^2 + (2-3)^2 + (3-3)^2)/3 = 2/3
+			// stddev = sqrt(2/3) ≈ 0.816
+			// CV = 0.816/3 ≈ 0.272
+			want:      0.272,
+			tolerance: 0.01,
+		},
+		{
+			name: "severe imbalance",
+			workloads: []RebalanceWorkload{
+				{Pane: 1, TaskCount: 10},
+				{Pane: 2, TaskCount: 0},
+				{Pane: 3, TaskCount: 0},
+			},
+			// mean = 10/3 ≈ 3.33
+			// variance = ((10-3.33)^2 + (0-3.33)^2 + (0-3.33)^2)/3 ≈ 22.22
+			// stddev ≈ 4.71
+			// CV ≈ 4.71/3.33 ≈ 1.414
+			want:      1.414,
+			tolerance: 0.01,
+		},
+		{
+			name: "all zero tasks",
+			workloads: []RebalanceWorkload{
+				{Pane: 1, TaskCount: 0},
+				{Pane: 2, TaskCount: 0},
+			},
+			want:      0, // No tasks = balanced
+			tolerance: 0.001,
+		},
+	}
+
+	for _, tt := range tests {
+		t.Run(tt.name, func(t *testing.T) {
+			got := calculateImbalanceScore(tt.workloads)
+			diff := got - tt.want
+			if diff < 0 {
+				diff = -diff
+			}
+			if diff > tt.tolerance {
+				t.Errorf("calculateImbalanceScore() = %v, want %v (tolerance %v)", got, tt.want, tt.tolerance)
+			}
+		})
+	}
+}
